SELECT COUNT(*) AS full_registration_count
FROM npo_registrations
WHERE status = 'Registered';

SELECT COUNT(*) AS total_active_npos
FROM npo_registrations
WHERE status = 'Registered';

SELECT status, COUNT(*) AS num_npos
FROM npo_registrations
GROUP BY status;

SELECT npo_type_name
FROM npo_types
LIMIT 1;

SELECT COUNT(*) AS total_registered_npos
FROM npo_registrations
WHERE status = 'Registered';

SELECT npo_type_id, npo_type_name, description
FROM npo_types
WHERE npo_type_name = 'Social Services';
